## 2.  C/C++ stub implementation – **pcapng_stubs.cpp**

```cpp
/* ----------------------------------------------------------------------
   OCaml bindings for libpcapng (C++ iterator over frames)

   Compile with a C++ compiler and link with the libpcapng library,
   e.g.:

       ocamlc -c -custom -ccopt "-std=c++17 -I$(PCAPNG_INC)" \
               -ccopt "-lpcapng" pcapng_stubs.cpp

   The file is deliberately written as a single translation unit that
   contains:
   * the thin C++ wrapper around libpcapng,
   * the OCaml custom block definition,
   * the three public primitives exposed in the .mli file.
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE               // avoid name clashes with stdlib
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/signals.h>

#include <string>
#include <exception>

/* ----------------------------------------------------------------------
   1.  Minimal C++ wrapper around libpcapng
   ---------------------------------------------------------------------- */

/*  The real library header(s) – replace with the actual path(s) */
#include <libpcapng/pcapng.hpp>   // <-- adjust to your installation

/*  The C++ class we expose.  It owns a libpcapng::PcapngFile
    instance and provides a simple `for_each_frame` method that calls
    a user supplied functor for every frame.                                            */
class pcapng_handle {
public:
    explicit pcapng_handle(const std::string& filename) {
        // The libpcapng API may throw; we translate to OCaml later.
        file_ = new libpcapng::PcapngFile(filename);
    }

    ~pcapng_handle() {
        delete file_;
    }

    // Disable copy – we only allow move semantics via the custom block.
    pcapng_handle(const pcapng_handle&) = delete;
    pcapng_handle& operator=(const pcapng_handle&) = delete;

    // The iterator: for each frame we invoke the supplied C++ functor.
    template <class F>
    void for_each_frame(F&& f) const {
        for (auto it = file_->begin(); it != file_->end(); ++it) {
            const libpcapng::Frame& fr = *it;   // <-- whatever the library provides
            f(fr);
        }
    }

private:
    libpcapng::PcapngFile* file_;   // owned
};

/* ----------------------------------------------------------------------
   2.  OCaml custom block that holds a `pcapng_handle*`
   ---------------------------------------------------------------------- */

static void pcapng_finalize(value v) {
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v);
    delete h;
}

static struct custom_operations pcapng_ops = {
    "org.example.pcapng_handle",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Helper: allocate a custom block wrapping a freshly constructed handle */
static value caml_pcapng_wrap_handle(pcapng_handle* h) {
    CAMLparam0();
    CAMLlocal1(block);
    block = caml_alloc_custom(&pcapng_ops, sizeof(pcapng_handle*), 0, 1);
    pcapng_handle **dst = (pcapng_handle **)Data_custom_val(block);
    *dst = h;
    CAMLreturn(block);
}

/* ----------------------------------------------------------------------
   3.  Conversion from libpcapng::Frame -> OCaml `frame` record
   ---------------------------------------------------------------------- */

static value caml_frame_of_lib(const libpcapng::Frame& fr) {
    CAMLparam0();
    CAMLlocal4(rec, ts_val, caplen_val, len_val);
    CAMLlocal1(data_val);

    /* 1) timestamp – the library may expose it as a double or as a struct.
       We assume a `double seconds` field here; adapt if needed.                */
    double ts = fr.timestamp();                 // <-- adjust accessor
    ts_val = caml_copy_double(ts);

    /* 2) captured length and original length */
    int caplen = static_cast<int>(fr.captured_len()); // <-- adjust accessor
    int len    = static_cast<int>(fr.original_len()); // <-- adjust accessor
    caplen_val = Val_int(caplen);
    len_val    = Val_int(len);

    /* 3) raw packet bytes – we allocate a OCaml Bytes.t and copy the data */
    const unsigned char* payload = fr.data();    // <-- adjust accessor
    data_val = caml_alloc_string(caplen);
    memcpy(String_val(data_val), payload, static_cast<size_t>(caplen));

    /* 4) build the OCaml record { ts; caplen; len; data } */
    rec = caml_alloc_tuple(4);
    Store_field(rec, 0, ts_val);
    Store_field(rec, 1, caplen_val);
    Store_field(rec, 2, len_val);
    Store_field(rec, 3, data_val);

    CAMLreturn(rec);
}

/* ----------------------------------------------------------------------
   4.  Primitive: open_file : string -> t
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_pcapng_open(value v_filename) {
    CAMLparam1(v_filename);
    CAMLlocal1(v_handle);
    const char* c_name = String_val(v_filename);
    try {
        pcapng_handle* h = new pcapng_handle(std::string(c_name));
        v_handle = caml_pcapng_wrap_handle(h);
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    } catch (...) {
        caml_failwith("pcapng: unknown C++ exception while opening file");
    }
    CAMLreturn(v_handle);
}

/* ----------------------------------------------------------------------
   5.  Primitive: iter : t -> (frame -> unit) -> unit
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_pcapng_iter(value v_handle, value v_cb) {
    CAMLparam2(v_handle, v_cb);
    CAMLlocal1(v_frame);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);

    /* The callback we will pass to the C++ iterator.  It converts the
       libpcapng::Frame to an OCaml value and then invokes the OCaml
       closure.  Any OCaml exception is re‑thrown as a C++ exception so
       that the outer loop can abort.                                            */
    struct OcamlCallback {
        value cb;
        OcamlCallback(value cb_) : cb(cb_) {}
        void operator()(const libpcapng::Frame& fr) const {
            CAMLparam0();
            CAMLlocal1(v_frame);
            v_frame = caml_frame_of_lib(fr);
            /* The OCaml callback may raise; caml_callback_exn returns the
               exception as a value which we then raise as a C++ exception. */
            value result = caml_callback_exn(cb, v_frame);
            if (Is_exception_result(result)) {
                // Extract the OCaml exception and re‑throw it as C++.
                // The exception value is stored in Field(result,0).
                value exn = Field(result, 0);
                caml_raise(exn);   // This long‑jumps back to OCaml land.
            }
            CAMLreturn0;
        }
    };

    try {
        OcamlCallback cb_wrapper(v_cb);
        h->for_each_frame(cb_wrapper);
    } catch (caml_exception) {
        /* The long‑jump from `caml_raise` lands here; we simply let the
           OCaml runtime propagate the exception, i.e. we return without
           catching it. */
        caml_raise_constant(*caml_named_value("Stdlib__Exception") /* dummy */);
        /* The above line is never reached; it only silences the compiler. */
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    } catch (...) {
        caml_failwith("pcapng: unknown C++ exception while iterating");
    }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   6.  Primitive: close : t -> unit
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    /* The custom finalizer already deletes the C++ object, but we allow
       an explicit close that clears the pointer so that a second call is
       a harmless no‑op.                                                            */
    pcapng_handle **ph = (pcapng_handle **)Data_custom_val(v_handle);
    if (*ph != nullptr) {
        delete *ph;
        *ph = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   7.  Register the primitives (for ocamlopt -custom or dynlink)
   ---------------------------------------------------------------------- */

static struct caml_named_value {
    const char *name;
    value (*fn)(value);
} caml_prims[] = {
    {"pcapng_open",  caml_pcapng_open},
    {"pcapng_iter",  caml_pcapng_iter},
    {"pcapng_close", caml_pcapng_close},
    {NULL, NULL}
};

extern "C" void caml_register_named_values(void) {
    for (int i = 0; caml_prims[i].name != NULL; ++i) {
        caml_register_named_value(caml_prims[i].name, caml_prims[i].fn);
    }
}

/* The above `caml_register_named_values` is automatically called by the
   OCaml runtime when the shared library is loaded (via `Dynlink` or when
   linking a custom native executable).  If you prefer to register the
   primitives manually, you can replace the whole function with:

       CAMLprim value caml_pcapng_open(value);
       CAMLprim value caml_pcapng_iter(value, value);
       CAMLprim value caml_pcapng_close(value);

   and then add the following lines to your `dune` file (or Makefile):

       (foreign_stubs
        (language c)
        (names pcapng_stubs)
        (flags (:standard -std=c++17))
        (libraries pcapng))   // link with the real libpcapng library
   ---------------------------------------------------------------------- */
```

